from lxml import etree
import io

def process_soap_request(xml_content):
    # Enable DTD validation
    parser = etree.XMLParser(load_dtd=True, no_network=False, resolve_entities=True, subsig=True)
    
    try:
        # Parse the XML content with DTD validation
        root = etree.fromstring(xml_content, parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Check if it's a valid SOAP envelope
    soap_ns = "http://schemas.xmlsoap.org/soap/envelope/"
    envelope = root.find(f".//{{{soap_ns}}}Envelope")
    
    if envelope is None:
        raise ValueError("Invalid SOAP envelope")
    
    # Extract the body
    body = envelope.find(f".//{{{soap_ns}}}Body")
    
    if body is None:
        raise ValueError("SOAP body not found")
    
    # Return the body content as string
    return etree.tostring(body, encoding='unicode', method='xml')

